// 1. 取得上一個節點傳進來的資料
const inputData = $input.first().json;

// 2. 提取準備要發送的回覆內容
const replyText = inputData.reply_text || "";

// 3. 語言偵測 (檢查回覆內容中是否包含中文字)
const hasHanzi = /[\u4e00-\u9fa5]/.test(replyText);

let language = "English";
if (hasHanzi) {
    language = "Chinese";
}

// 4. 輸出結果給下一個節點 (HTTP Request)
return [{
    json: {
        language: language,
        reply: $input.first().json.output.agent_reply
    }
}];

parameters.inputSchema:
{
  "type": "object",
  "properties": {
    "agent_reply": {
      "type": "string",
      "description": "The friendly conversational reply to the user. Must be in the user's language."
    },
    "summary": {
      "type": "string",
      "description": "A short summary of the meal, or 'Chat' if the user is just chatting."
    },
    "details": {
      "type": "array",
      "description": "List of food items logged. Leave this array EMPTY [] if the user is just asking a question and not logging a meal.",
      "items": {
        "type": "object",
        "properties": {
          "meal_time": { "type": "string", "enum": ["breakfast", "lunch", "dinner", "snack"] },
          "food_name": { "type": "string" },
          "food_name_en": { "type": "string" },
          "main_ingredient": { "type": "string" },
          "cooking_method": { "type": "string" },
          "sauce_or_seasoning": { "type": "string" },
          "style": { "type": "string" },
          "nutrition": {
            "type": "object",
            "properties": {
              "calories": { "type": "number" },
              "protein": { "type": "number" },
              "fat": { "type": "number" },
              "carbohydrates": { "type": "number" },
              "fiber": { "type": "number" }
            }
          }
        }
      }
    }
  },
  "required": ["agent_reply", "summary", "details"]
}

