let replyItem="";

// 1. 取得上一個節點傳進來的資料
const inputData = $input.first().json;

// 2. 提取準備要發送的回覆內容
const replyText = inputData.reply_text || "";

// 3. 語言偵測 (檢查回覆內容中是否包含中文字)
const hasHanzi = /[\u4e00-\u9fa5]/.test(replyText);

let language = "English";
if (hasHanzi) {
    language = "Chinese";
    replyItem="發現系統出現錯誤，請再發問試試或聯聯系統服務員";
}
else{
  replyItem="System Error is found, please try again or call system administrator";

}

// 4. 輸出結果給下一個節點 (HTTP Request)
return [{
    json: {
        language: language,
        reply: replyItem
    }
}];
